mapper.select:
select 
from (
    select ,
           ST_Distance(
               a.location::geography,
               ST_SetSRID(ST_MakePoint(#{longitude}, #{latitude}), 4326)::geography
           ) as distanceMeters
    from attractions a
    where a.location is not null
      and ST_DWithin(
          a.location::geography,
          ST_SetSRID(ST_MakePoint(#{longitude}, #{latitude}), 4326)::geography,
          #{radiusMeters}
      )


              and exists (
                  select 1
                  from attraction_saves s
                  where s.attraction_id = a.id
                    and s.user_id = #{viewerUserId}
              )


              and false


    order by distanceMeters asc, a.title asc, a.id asc
    limit #{limit}
) a

order by a.distanceMeters asc, a.title asc, a.id asc, t.name asc

select 

where a.id = #{attractionId}
order by t.name asc

mapper.insert:
merge into attraction_popularity_stats as stats using ( values
( #{delta.attractionId}, #{delta.delta} )
) as incoming (attraction_id, delta) on stats.attraction_id = incoming.attraction_id when matched then update set favorite_count = greatest(0, stats.favorite_count + incoming.delta), updated_at = current_timestamp when not matched then insert (attraction_id, favorite_count, updated_at) values (incoming.attraction_id, greatest(0, incoming.delta), current_timestamp)

merge into attraction_popularity_stats as stats using ( values
( #{delta.attractionId}, #{delta.delta} )
) as incoming (attraction_id, delta) on stats.attraction_id = incoming.attraction_id when matched then update set save_count = greatest(0, stats.save_count + incoming.delta), updated_at = current_timestamp when not matched then insert (attraction_id, save_count, updated_at) values (incoming.attraction_id, greatest(0, incoming.delta), current_timestamp)
